package com.debopam.llmcouncil.model; import org.springframework.stereotype.Component; import java.util.Map; import java.util.NoSuchElementException; @Component public class ModelRegistry { private Map<String, ModelProfile> profiles = Map.of(); private Map<String, ModelClient> clients = Map.of(); public void register(Map<String, ModelProfile> profiles, Map<String, ModelClient> clients){ this.profiles=Map.copyOf(profiles); this.clients=Map.copyOf(clients);} public ModelProfile model(String id){ var p=profiles.get(id); if(p==null) throw new NoSuchElementException("Unknown model: "+id); return p;} public ModelClient clientForModel(String id){ var c=clients.get(id); if(c==null) throw new NoSuchElementException("No client configured for model: "+id); return c;} }
